// Twisted Vessel — a hollow ceramic vase with an elegant profile (wide belly,
// pinched neck, flared rim), a true opening at the top, and a graceful surface
// twist. Twisting a fluted (lobed) body is the signature: a plain surface of
// revolution would be invariant under z-twist, so the vertical flutes are what
// make the spiral read.
//
// COLOR-BY-LABEL strategy (sdf.md): smoothUnion does NOT propagate inner
// labels, and labelled subtrees mesh SEPARATELY then hard-union — so if we
// labelled the rim *inside* the silhouette before shelling, the shell would be
// applied to each labelled subtree on its own and split into two disconnected
// thin walls (multiple components). Instead:
//   1. The ENTIRE shelled, twisted, hollowed vase is built as ONE labelled
//      solid ('glaze') — a single watertight wall.
//   2. A separate SOLID gold rim band ('rim') is HARD-unioned onto the lip.
//      Being its own labelled solid, it keeps its label; overlapping the wall
//      generously keeps the whole model a single component.
// Painting is purely by-label, so the saved file stays tiny (no per-triangle
// ID lists → ~hundreds of KB instead of 16 MB).
const { sdf } = api;

// ---- Outer silhouette: a stack of blended ellipsoids up Z ------------------
// rx=ry=radius, rz=segment half-height. Moderate smooth-union k so the belly /
// neck / rim curvature is PRESERVED (too-large k flattens it into a cylinder).
const foot   = sdf.ellipsoid(7,   7,   4).translate(0, 0, 1);    // small foot-ring
const lower  = sdf.ellipsoid(12,  12,  8).translate(0, 0, 9);    // swelling lower belly
const belly  = sdf.ellipsoid(14.5,14.5, 9).translate(0, 0, 17);  // widest point
const upper  = sdf.ellipsoid(9.5, 9.5,  8).translate(0, 0, 26);  // shoulder tapering in
const neck   = sdf.ellipsoid(5.8, 5.8,  6).translate(0, 0, 34);  // pinched neck
const rim    = sdf.ellipsoid(8.5, 8.5, 2.6).translate(0, 0, 42); // flared lip

let silhouette = foot
  .smoothUnion(lower, 3.5)
  .smoothUnion(belly, 4)
  .smoothUnion(upper, 3.5)
  .smoothUnion(neck, 2.8)
  .smoothUnion(rim, 2.2);

// ---- Flutes: a ring of shallow ridges that hug the belly --------------------
// Each flute is a SHORT capsule confined to the wide belly band (z 11..25), so
// it never pokes past the narrow foot or neck. Crucially the flute radius is
// kept just BELOW the belly wall radius so the ridge sits proud by ~1 unit, not
// sticking out as a spike. An ellipsoidal flute (fatter in the middle) tapers
// its own ends, blending into the wall where the body narrows.
const ridge = sdf.ellipsoid(1.9, 1.9, 10).translate(13.2, 0, 16);
const flutes = ridge.polarArray(10, { axis: 'z' });
silhouette = silhouette.smoothUnion(flutes, 1.6);

// ---- The twist (the SDF signature) -----------------------------------------
// ~5 deg/unit over the fluted span gives a clear, graceful spiral on the belly.
silhouette = silhouette.twist(5, 'z');

// ---- Hollow it: constant-thickness shell + carved-open mouth ---------------
const wall = silhouette.shell(1.7);

// Mouth cutter reaching from above the rim down into the belly, narrower than
// the neck bore so a clean rim survives. Plus an interior scoop so the inside
// reads as a real cavity rather than a bored tube.
const mouth  = sdf.cylinder(4.8, 44).translate(0, 0, 32);
const cavity = sdf.ellipsoid(11, 11, 12).translate(0, 0, 17);

// The whole hollow twisted vase is ONE smooth watertight body → label 'glaze'.
const glaze = wall.subtract(mouth).subtract(cavity).label('glaze');

// ---- Gold rim band: a separate SOLID labelled ring on the lip --------------
// A torus tracing the OUTER lip of the flared rim so the gold reads as a crisp
// band wrapping the visible edge (not a sliver hidden in the bore). The flared
// rim ellipsoid is r=8.5 at z=42; we sit the torus' major radius at the outer
// wall (~8.0) and centre it ON the lip's top edge (z≈42.4) with a fat-enough
// minor radius that the band caps the rim's crown. Its tube straddles the wall
// (wall is 1.7 thick) so it fuses into ONE component, while its own label paints
// it gold.
const rimBand = sdf.torus(8.0, 1.9).translate(0, 0, 42.4).label('rim');

// HARD union keeps BOTH 'glaze' and 'rim' labels; the overlap keeps it 1 part.
const vessel = sdf.union(glaze, rimBand);

return vessel.build({ edgeLength: 0.45 });

